  // --- Claim: enchantment ≥ 8 → 50% reimbursement ---
  it.todo("claim: steel sword ench 9, damage 1000 G → payout 400 G (500 minus 100 deductible)");
  it.todo("claim: dragon sword ench 8, damage 1000 G → payout 400 G (high-ench clause applies first, then deductible)");

  // --- Claim: dragon material → full reimbursement ---
  it.todo("claim: dragon sword ench 5, damage 800 G → payout 700 G (dragon clause only: full reimbursement minus deductible)");
  it.todo("claim: dragon sword ench 9, damage 1000 G → payout 400 G (both clauses apply; 50% rule wins, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("claim: dragon attack damages insured sword (500 G) and amulet (300 G) → payout 600 G (deductible applied once per damaged item)");

  // --- Claim: multiple items of the same type ---
  it.todo("policy with two swords: insurance sum is 2000 G (2 × 1000)");
  it.todo("claim with two sword damages against a 2-sword policy: each entry is its own damage with its own deductible");

  // --- Payout rounding (rounded DOWN) ---
  it.todo("payout yielding 350.5 G rounds DOWN to 350 G");

