const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const COMPONENT_BLOCK_OF_3_PRICE = 60;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { type: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer?: Customer; steps: QuoteStep[] };

function groupByType(items: Item[]): Map<string, Item[]> {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
}

function isHighlyEnchanted(item: Item): boolean {
  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
}

function calculateItemPremium(item: Item): number {
  const itemBase = BASE_PREMIUMS[item.type];
  const curseSurcharge = item.cursed ? itemBase * CURSE_SURCHARGE_RATE : 0;
  const highEnchantmentSurcharge = isHighlyEnchanted(item)
    ? itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE
    : 0;
  return itemBase + curseSurcharge + highEnchantmentSurcharge;
}

function calculateGroupPremium(type: string, group: Item[]): number {
  if (COMPONENT_TYPES.has(type) && group.length === 3) {
    return COMPONENT_BLOCK_OF_3_PRICE;
  }
  return group.reduce((sum, item) => sum + calculateItemPremium(item), 0);
}

function calculateGroupBareBase(type: string, group: Item[]): number {
  if (COMPONENT_TYPES.has(type) && group.length === 3) {
    return COMPONENT_BLOCK_OF_3_PRICE;
  }
  return group.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
}

function calculateBasePremium(items: Item[]): number {
  return Array.from(groupByType(items)).reduce(
    (total, [type, group]) => total + calculateGroupPremium(type, group),
    0,
  );
}

function calculateBareBasePremium(items: Item[]): number {
  return Array.from(groupByType(items)).reduce(
    (total, [type, group]) => total + calculateGroupBareBase(type, group),
    0,
  );
}

export function runScenario(scenario: unknown): { results: { premium: number }[] } {
  const { customer, steps } = scenario as Scenario;
  const items = steps[0].items;
  const basePremium = calculateBasePremium(items);
  const bareBasePremium = calculateBareBasePremium(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  const loyaltyDiscount =
    (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS
      ? bareBasePremium * LOYALTY_DISCOUNT_RATE
      : 0;
  const premium =
    basePremium - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
  return { results: [{ premium }] };
}

